import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { supabase } from '../../config/supabase';
import { Link } from 'react-router-dom';
import { formatDistanceToNow } from 'date-fns';
import { fr } from 'date-fns/locale';

const ScrollingProposals = () => {
  const [proposals, setProposals] = useState([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isTransitioning, setIsTransitioning] = useState(false);

  // Fetch latest proposals
  useEffect(() => {
    const fetchProposals = async () => {
      try {
        const { data, error } = await supabase
          .from('proposals')
          .select(`
            id,
            subject,
            one_sentence,
            created_at,
            yes_count,
            no_count,
            profile:profiles!proposals_user_id_fkey(
              first_name,
              last_name,
              portrait_url,
              province
            )
          `)
          .eq('status', 'published')
          .order('created_at', { ascending: false })
          .limit(10);

        if (error) throw error;
        setProposals(data || []);
      } catch (error) {
        console.error('Error fetching scrolling proposals:', error);
      }
    };

    fetchProposals();
  }, []);

  // Auto-scroll every 10 seconds
  useEffect(() => {
    if (proposals.length === 0) return;

    const interval = setInterval(() => {
      setIsTransitioning(true);
      setTimeout(() => {
        setCurrentIndex((prev) => (prev + 1) % proposals.length);
        setIsTransitioning(false);
      }, 500);
    }, 10000);

    return () => clearInterval(interval);
  }, [proposals.length]);

  if (proposals.length === 0) {
    return (
      <div style={{ textAlign: 'center', padding: 'var(--space-xl)', color: 'var(--gray-500)' }}>
        Chargement des propositions...
      </div>
    );
  }

  const currentProposal = proposals[currentIndex];
  const totalVotes = (currentProposal?.yes_count || 0) + (currentProposal?.no_count || 0);

  return (
    <div className="scrolling-container">
      <AnimatePresence mode="wait">
        <motion.div
          key={currentProposal.id}
          className="scrolling-item"
          initial={{ opacity: 0, x: 50 }}
          animate={{ opacity: 1, x: 0 }}
          exit={{ opacity: 0, x: -50 }}
          transition={{ duration: 0.5 }}
        >
          {/* User Avatar */}
          <img
            src={currentProposal.profile?.portrait_url || '/images/default-avatar.png'}
            alt={currentProposal.profile?.first_name}
            className="scrolling-item-avatar"
          />

          {/* Content */}
          <div className="scrolling-item-content">
            <div className="scrolling-item-name">
              {currentProposal.profile?.first_name} {currentProposal.profile?.last_name}
              {currentProposal.profile?.province && (
                <span style={{ 
                  marginLeft: 'var(--space-sm)',
                  fontSize: '0.75rem',
                  color: 'var(--gray-500)'
                }}>
                  📍 {currentProposal.profile.province}
                </span>
              )}
            </div>
            <div className="scrolling-item-subject">
              {currentProposal.subject}
            </div>
            <div className="scrolling-item-excerpt">
              {currentProposal.one_sentence}
            </div>
            <div style={{ 
              display: 'flex', 
              gap: 'var(--space-md)', 
              marginTop: 'var(--space-sm)',
              fontSize: '0.85rem'
            }}>
              <span style={{ color: 'var(--success)', fontWeight: 600 }}>
                ✅ {currentProposal.yes_count || 0} OUI
              </span>
              <span style={{ color: 'var(--error)', fontWeight: 600 }}>
                ❌ {currentProposal.no_count || 0} NON
              </span>
              <span style={{ color: 'var(--gray-500)' }}>
                🗳️ {totalVotes} votes
              </span>
              <span style={{ color: 'var(--gray-500)' }}>
                🕐 {formatDistanceToNow(new Date(currentProposal.created_at), { 
                  addSuffix: true, 
                  locale: fr 
                })}
              </span>
            </div>
          </div>

          {/* View Link */}
          <Link
            to={`/proposals/${currentProposal.id}`}
            style={{
              flexShrink: 0,
              padding: 'var(--space-sm) var(--space-md)',
              background: 'var(--drc-blue)',
              color: 'white',
              borderRadius: 'var(--radius-full)',
              textDecoration: 'none',
              fontSize: '0.85rem',
              fontWeight: 600
            }}
          >
            Voir →
          </Link>
        </motion.div>
      </AnimatePresence>

      {/* Progress Dots */}
      <div style={{ 
        display: 'flex', 
        justifyContent: 'center', 
        gap: 'var(--space-sm)',
        marginTop: 'var(--space-md)'
      }}>
        {proposals.map((_, index) => (
          <button
            key={index}
            onClick={() => setCurrentIndex(index)}
            style={{
              width: '8px',
              height: '8px',
              borderRadius: '50%',
              border: 'none',
              background: index === currentIndex ? 'var(--drc-blue)' : 'var(--gray-300)',
              cursor: 'pointer',
              transition: 'all 0.3s ease',
              transform: index === currentIndex ? 'scale(1.5)' : 'scale(1)'
            }}
            aria-label={`Proposition ${index + 1}`}
          />
        ))}
      </div>
    </div>
  );
};

export default ScrollingProposals;
